-- ========== FISH — Intermediate / Advanced ==========
('Apistogramma', 'Apistogramma spp.', 'fish', 8, 20, 24, 29, 5.0, 7.0, 'semi-aggressive', 'intermediate', 'bottom/middle', 'Colorful dwarf cichlids. Males are territorial. Need soft, acidic water and a well-planted tank with caves. Many beautiful species.'),
('German Blue Ram', 'Mikrogeophagus ramirezi', 'fish', 7, 20, 26, 30, 5.5, 7.0, 'peaceful', 'intermediate', 'bottom/middle', 'Stunning dwarf cichlid with electric blue and gold. Needs warm, pristine water. Sensitive to poor water quality. Short-lived (2-3 years).'),
('Yoyo / Striata Loach', 'Botia striata', 'fish', 10, 30, 23, 27, 6.0, 7.5, 'peaceful', 'intermediate', 'bottom', 'Attractive striped loach. Active, playful personality. Excellent snail control. Keep in groups of 4+. Needs hiding spots.'),
('Upside-Down Catfish', 'Synodontis nigriventris', 'fish', 10, 30, 22, 27, 6.0, 7.5, 'peaceful', 'easy', 'middle/bottom', 'Swims inverted to feed from surface and underside of decor. Fascinating behavior. Nocturnal — provide caves and dim lighting.'),
('Boesemani Rainbowfish', 'Melanotaenia boesemani', 'fish', 12, 30, 24, 28, 7.0, 8.0, 'peaceful', 'intermediate', 'middle/top', 'Split blue/orange coloring that intensifies with age. Males are spectacular. Active, needs swimming room and good filtration.'),
('Threadfin Rainbowfish', 'Iriatherina werneri', 'fish', 5, 10, 24, 28, 5.5, 7.5, 'peaceful', 'intermediate', 'middle/top', 'Delicate nano rainbow with thread-like fin extensions. Peaceful and shy — keep with gentle tankmates only.'),
('Discus', 'Symphysodon spp.', 'fish', 20, 55, 28, 32, 5.5, 7.0, 'peaceful', 'advanced', 'middle', 'The "king of the aquarium." Demands pristine water, high temps, and a varied diet. Keep in groups. Expensive but breathtaking.'),
('Clown Killifish', 'Epiplatys annulatus', 'fish', 4, 5, 23, 27, 6.0, 7.0, 'peaceful', 'intermediate', 'top', 'Tiny surface-dwelling killifish with rocket-shaped tail. Beautiful micro predator. Great for nano planted tanks.'),
('Gardneri Killifish', 'Fundulopanchax gardneri', 'fish', 6, 10, 22, 26, 6.0, 7.5, 'semi-aggressive', 'intermediate', 'top/middle', 'Brilliantly colored killifish. Males are stunning blue/red. Can be jumpy — tight-fitting lid essential. Males territorial.'),
('Endlers Livebearer', 'Poecilia wingei', 'fish', 4, 5, 24, 30, 7.0, 8.5, 'peaceful', 'beginner', 'top/middle', 'Tiny, vivid cousin of the guppy. Males are spectacularly colored. Prolific breeders. Keep pure from guppy hybridization.'),

-- ========== FISH — Large / Advanced ==========
('Oscar', 'Astronotus ocellatus', 'fish', 35, 75, 23, 28, 6.0, 8.0, 'aggressive', 'intermediate', 'middle', 'Intelligent, personable large cichlid with dog-like personality. Grows fast, messy eater. Needs massive tank and powerful filtration.'),
('Red-Tailed Black Shark', 'Epalzeorhynchos bicolor', 'fish', 15, 55, 22, 27, 6.5, 7.5, 'aggressive', 'intermediate', 'bottom/middle', 'Striking jet-black body with vivid red tail. Highly territorial — one per tank. Chases similar-looking fish aggressively.'),
('Red-Bellied Pacu', 'Piaractus brachypomus', 'fish', 60, 250, 24, 28, 6.0, 7.5, 'peaceful', 'advanced', 'middle', 'Often mis-sold as a "vegetarian piranha." Gets ENORMOUS — needs a pond-sized setup. Do not impulse buy! Herbivore.'),
('Silver Arowana', 'Osteoglossum bicirrhosum', 'fish', 90, 300, 24, 30, 6.0, 7.0, 'aggressive', 'advanced', 'top', 'Massive, prehistoric surface predator. Jumps out of tanks — heavy, tight lid mandatory. Only for expert fishkeepers with enormous setups.'),
('Convict Cichlid', 'Amatitlania nigrofasciata', 'fish', 15, 30, 20, 28, 6.0, 8.0, 'aggressive', 'beginner', 'middle/bottom', 'Hardy, prolific breeder. Very aggressive when guarding fry. Black and white striped. Good beginner cichlid if you want personality.'),
('Jack Dempsey Cichlid', 'Rocio octofasciata', 'fish', 25, 55, 22, 28, 6.5, 8.0, 'aggressive', 'intermediate', 'middle/bottom', 'Beautiful iridescent spots on dark body. Named after the boxer — appropriately aggressive. Electric Blue variant is popular.'),
('Firemouth Cichlid', 'Thorichthys meeki', 'fish', 17, 30, 23, 28, 6.5, 8.0, 'semi-aggressive', 'easy', 'middle/bottom', 'Flares bright red throat in territorial displays. Less aggressive than many Central American cichlids. Good "gateway" cichlid.');

